    'vid.intro': 'Chronicles, reports and highlights. All content comes from our Instagram <a href="https://www.instagram.com/juguemabasquet" target="_blank" style="color:var(--orange);font-weight:700;text-decoration:none;">@juguemabasquet</a>.',
