let currentLang = localStorage.getItem('jab-lang') || 'ca';

function setLang(lang) {
  currentLang = lang;
  localStorage.setItem('jab-lang', lang);
  // Actualitzar botons
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.classList.toggle('active', btn.textContent.toLowerCase() === lang);
  });
  // Actualitzar atribut lang del document
  document.documentElement.lang = lang;
  // Aplicar traduccions
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const val = TRANSLATIONS[lang] && TRANSLATIONS[lang][key];
    if (val !== undefined) el.innerHTML = val;
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const key = el.getAttribute('data-i18n-ph');
    const val = TRANSLATIONS[lang] && TRANSLATIONS[lang][key];
    if (val !== undefined) el.placeholder = val;
  });
  // Actualitzar pseudo-elements CSS (no admeten data-i18n)
  const destacatTxt = { ca: 'DESTACAT', en: 'FEATURED', es: 'DESTACADO' };
  document.documentElement.style.setProperty('--txt-destacat', `'${destacatTxt[lang] || 'DESTACAT'}'`);

  // Actualitzar title de la pàgina
  const titles = {
    ca: 'Juguem a Bàsquet — El bàsquet que ens uneix',
    en: 'Juguem a Bàsquet — Basketball that unites us',
    es: 'Juguem a Bàsquet — El baloncesto que nos une'
  };
  document.title = titles[lang];
  setupProposaBtn();
  if (window.jabMap) window.jabMap.closePopup();
  if (window.jabRenderLlista) window.jabRenderLlista();
}

// Aplicar idioma guardat al carregar
document.addEventListener('DOMContentLoaded', () => {
  if (currentLang !== 'ca') setLang(currentLang);
  else setLang('ca');
});

// Botiga — selector de color i talla
function switchColor(imgId, src, dot) {
  document.getElementById(imgId).src = src;
  dot.closest('.merch-colors').querySelectorAll('.color-dot').forEach(d => {
    d.classList.remove('active');
    d.style.borderColor = 'transparent';
  });
  dot.classList.add('active');
  dot.style.borderColor = 'var(--orange)';
}
document.addEventListener('click', function(e) {
  if (e.target.classList.contains('size-btn')) {
    e.target.closest('.merch-sizes').querySelectorAll('.size-btn').forEach(b => b.classList.remove('active'));
    e.target.classList.add('active');
  }
});

